using System;
using System.Collections.Concurrent;
using System.Reflection;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            DrainStaticQueue();
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            DrainStaticQueue();
        }

        private static void DrainStaticQueue()
        {
            var field = typeof(NotificationService).GetField("_queue", BindingFlags.NonPublic | BindingFlags.Static);
            if (field?.GetValue(null) is ConcurrentQueue<Notification> queue)
            {
                while (queue.TryDequeue(out _)) { }
            }
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");

            Assert.True((bool)successProp.GetValue(value));
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
        {
            // Use the controller's notification service (via base controller) to send notifications
            // Access the notificationService through reflection since it's protected
            var nsField = typeof(BaseController).GetField("notificationService", BindingFlags.NonPublic | BindingFlags.Instance | BindingFlags.Public);
            var ns = nsField.GetValue(_controller) as NotificationService;
            ns.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
            ns.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");

            var result = _controller.GetNotifications();
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(value);

            Assert.Equal(2, count);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var nsField = typeof(BaseController).GetField("notificationService", BindingFlags.NonPublic | BindingFlags.Instance | BindingFlags.Public);
            var ns = nsField.GetValue(_controller) as NotificationService;
            for (int i = 0; i < 15; i++)
            {
                ns.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(value);

            Assert.Equal(10, count);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccessJson()
        {
            var result = _controller.MarkAsRead(1);
            Assert.IsType<JsonResult>(result);

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }
    }
}

