        public void TestSendEntityNotification(string entityType, string entityId, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, operation);
        }

        public void TestSendEntityNotification(string entityType, string entityId, string displayName, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, displayName, operation);
        }

        public NotificationService GetNotificationService()
        {
            return notificationService;
        }
    }

    public class BaseControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly TestableController _controller;

        public BaseControllerTests()
        {
            DrainStaticQueue();
            _context = TestHelpers.CreateContext();
            _controller = new TestableController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            DrainStaticQueue();
        }

        private static void DrainStaticQueue()
        {
            var field = typeof(NotificationService).GetField("_queue", BindingFlags.NonPublic | BindingFlags.Static);
            if (field?.GetValue(null) is ConcurrentQueue<Notification> queue)
            {
                while (queue.TryDequeue(out _)) { }
            }
        }

        [Fact]
        public void SendEntityNotification_WithDisplayName_SendsNotification()
        {
            _controller.TestSendEntityNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _controller.GetNotificationService().ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendEntityNotification_WithoutDisplayName_SendsNotification()
        {
            _controller.TestSendEntityNotification("Course", "42", EntityOperation.DELETE);

            var notification = _controller.GetNotificationService().ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Course (ID: 42)", notification.Message);
        }

        [Fact]
        public void Dispose_DisposesContextAndNotificationService()
        {
            var context = TestHelpers.CreateContext();
            var controller = new TestableController(context);

            // Should not throw
            var exception = Record.Exception(() => controller.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void Constructor_SetsDbContext()
        {
