using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
        }

        [Theory]
        [InlineData(10, 5, 2)]
        [InlineData(10, 3, 4)]
        [InlineData(1, 10, 1)]
        [InlineData(0, 10, 0)]
        [InlineData(11, 5, 3)]
        public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Theory]
        [InlineData(1, false)]
        [InlineData(2, true)]
        [InlineData(3, true)]
        public void HasPreviousPage_ReturnsCorrectly(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
            Assert.Equal(expected, list.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 3, true)]
        [InlineData(2, 3, true)]
        [InlineData(3, 3, false)]
        [InlineData(1, 1, false)]
        public void HasNextPage_ReturnsCorrectly(int pageIndex, int totalPages, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
            Assert.Equal(expected, list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 10);
            Assert.Equal(10, page1.Count);
            Assert.Equal(1, page1.First());
            Assert.Equal(10, page1.Last());
            Assert.Equal(1, page1.PageIndex);
            Assert.Equal(3, page1.TotalPages);

            var page2 = PaginatedList<int>.Create(source, 2, 10);
            Assert.Equal(10, page2.Count);
            Assert.Equal(11, page2.First());
            Assert.Equal(20, page2.Last());

            var page3 = PaginatedList<int>.Create(source, 3, 10);
            Assert.Equal(5, page3.Count);
            Assert.Equal(21, page3.First());
            Assert.Equal(25, page3.Last());
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<string>().AsQueryable();
            var result = PaginatedList<string>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_SinglePage_NoNavigation()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Reflection;
using System.Collections.Concurrent;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            // Drain the static queue before each test to avoid interference
            DrainStaticQueue();
            _service = new NotificationService();
        }

        public void Dispose()
        {
            _service.Dispose();
            DrainStaticQueue();
        }

        private static void DrainStaticQueue()
        {
            // Access the static queue via reflection to drain it
            var field = typeof(NotificationService).GetField("_queue", BindingFlags.NonPublic | BindingFlags.Static);
            if (field?.GetValue(null) is ConcurrentQueue<Notification> queue)
            {
                while (queue.TryDequeue(out _)) { }
            }
        }

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("Course (ID: 42)", notification.Message);
            Assert.Contains("updated", notification.Message);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_DequeueFIFO()
        {
            _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Contains("First", first.Message);
            Assert.Contains("Second", second.Message);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_GeneratesCorrectMessageForOperation(EntityOperation operation, string expectedVerb)
        {
            _service.SendNotification("Department", "5", "Math", operation);

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedVerb, notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void QueueCap_EnforcedAt500()
        {
            // Enqueue 510 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Drain and count
            int count = 0;
            while (_service.ReceiveNotification() != null)
                count++;

            Assert.True(count <= 500, $"Expected at most 500 notifications but got {count}");
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, but should not throw
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_SimpleOverload_SetsCorrectOperation()
        {
            _service.SendNotification("Instructor", "3", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("DELETE", notification.Operation);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("3", notification.EntityId);
        }
    }
}

