        {
            var course = SeedCourse();
            // Create a fake image file on disk
            var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var imgFile = Path.Combine(uploadsPath, "test_image.jpg");
            File.WriteAllBytes(imgFile, new byte[100]);

            // Update course to point to that image
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(course.CourseID);

            Assert.False(File.Exists(imgFile));
        }

        [Fact]
        public void EditPost_WithNewImage_ReplacesOldFile()
        {
            var course = SeedCourse();
            // Create old image file
            var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var oldImgFile = Path.Combine(uploadsPath, "old_image.jpg");
            File.WriteAllBytes(oldImgFile, new byte[50]);

            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/old_image.jpg";
            _context.SaveChanges();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var mockFile = CreateMockFile("new.png", 512, new byte[512]);
            var result = _controller.Edit(course, mockFile.Object);

            Assert.IsType<RedirectToActionResult>(result);
            // Old file should be deleted
            Assert.False(File.Exists(oldImgFile));
        }

        [Fact]
