            {
                CourseID = 3010,
                Title = "Exact5MB",
                Credits = 1,
                DepartmentID = dept.DepartmentID
            };
            // Exactly 5MB = 5 * 1024 * 1024 = 5242880
            var mockFile = CreateMockFile("exact.jpg", 5 * 1024 * 1024, new byte[5 * 1024 * 1024]);

            var result = _controller.Create(course, mockFile.Object);
            Assert.IsType<RedirectToActionResult>(result);
        }
    }
}

